display.text:
/**
 * baz-review — code review function.
 * Provides: baz-review skill (5-dimension review), baz_review_changes tool
 * (fetch a git diff), /review command.
 */

import { spawnSync } from "node:child_process";
import { existsSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { StringEnum } from "@earendil-works/pi-ai";
import { Type } from "typebox";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

const baseDir = dirname(fileURLToPath(import.meta.url));
const SKILL_FILE = join(baseDir, "SKILL.md");
const MAX_DIFF = 50 * 1024;

function git(args: string[], cwd: string): string {
  const r = spawnSync("git", args, { cwd, encoding: "utf-8", maxBuffer: 20 * 1024 * 1024 });
  return (r.stdout || "") + (r.stderr ? `\n[stderr]\n${r.stderr}` : "");
}

function branchBase(cwd: string): string {
  for (const ref of ["origin/main", "origin/master", "main", "master", "HEAD~1"]) {
    const r = spawnSync("git", ["rev-parse", "--verify", ref], { cwd, encoding: "utf-8" });
    if (r.status === 0 && r.stdout.trim()) return r.stdout.trim();
  }
  return "HEAD~1";
}

function truncate(s: string): string {
  return s.length > MAX_DIFF
    ? s.slice(0, MAX_DIFF) + `\n\n[... BAZ truncated at ${MAX_DIFF} bytes; call baz_review_changes again for the full diff ...]`
    : s;
}

function fetchDiff(scope: string, paths: string[] | undefined, cwd: string): string {
  let out = "";
  switch (scope) {
    case "last":
      out = git(["show", "--format=fuller", "HEAD"], cwd);
      break;
    case "branch": {
      const base = branchBase(cwd);
      out = git(["diff", `${base}...HEAD`], cwd);
      break;
    }
    case "paths":
      out = git(["diff", "--", ...(paths ?? [])], cwd);
      break;
    case "staged":
    default:
      out = git(["diff", "--cached"], cwd);
      break;
  }
  return truncate(out.trim());
}

export default function bazReview(pi: ExtensionAPI) {
  pi.on("resources_discover", async () => {
    const skillPaths: string[] = existsSync(SKILL_FILE) ? [SKILL_FILE] : [];
    return { skillPaths };
  });

  pi.on("before_agent_start", async (event) => {
    const block = `

## BAZ review

Code review function. Use the \`baz-review\` skill (load via \`/skill:baz-review\`) for the 5-dimension workflow and output format. Use \`baz_review_changes\` to fetch a git diff (scope: staged | last | branch | paths). \`/review [scope]\` kicks off a review. Guardrail snippets (security-checklist, careful, testing-requirements, etc.) are loadable via the \`baz_snippet\` tool from baz-guardrails.
`;
    return { systemPrompt: event.systemPrompt + block };
  });

  pi.registerTool({
    name: "baz_review_changes",
    label: "BAZ Review Changes",
    description:
      "Fetch a git diff for a BAZ code review. Returns the diff text. scope: 'staged' (default), 'last' (last commit), 'branch' (vs base branch), or 'paths' (requires paths).",
    promptSnippet: "Fetch a git diff for review (staged / last / branch / paths)",
    promptGuidelines: [
      "Use baz_review_changes to fetch a diff before a BAZ review instead of shelling out to git.",
    ],
    parameters: Type.Object({
      scope: StringEnum(["staged", "last", "branch", "paths"] as const, { description: "Diff scope" }),
      paths: Type.Optional(Type.Array(Type.String(), { description: "Paths (scope=paths)" })),
    }),
    async execute(_id, params, _signal, _onUpdate, ctx) {
      const diff = fetchDiff(params.scope, params.paths, ctx.cwd);
      return {
        content: [{ type: "text", text: diff || "(empty diff — nothing to review)" }],
        details: { scope: params.scope, cwd: ctx.cwd },
      };
    },
  });

  const KNOWN_SCOPES = new Set(["staged", "last", "branch"]);

  function runReview(args: string, ctx: { cwd: string }) {
    const arg = args.trim();
    const isPaths = arg !== "" && !KNOWN_SCOPES.has(arg);
    const scope = isPaths ? "paths" : arg || "staged";
    const paths = isPaths ? arg.split(/\s+/).filter(Boolean) : undefined;
    const label = isPaths ? arg : scope;
    const diff = fetchDiff(scope, paths, ctx.cwd);
    pi.sendUserMessage(
      [
        {
          type: "text",
          text: `Run a BAZ code review (scope: ${label}). Load the baz-review skill, review the diff across all 5 dimensions (code-quality, security, performance, testing, documentation), apply relevant guardrail snippets via baz_snippet, and output the BAZ report (Overall / Critical / Suggestions / Highlights, citing file:line). If truncated, call baz_review_changes with scope ${label}.\n\n\`\`\`diff\n${diff}\n\`\`\``,
        },
      ],
      { triggerTurn: true },
    );
  }

  pi.registerCommand("review", {
    description: "BAZ code review (staged | last | branch | <paths>)",
    getArgumentCompletions: (prefix: string) => {
      const f = ["staged", "last", "branch"].filter((o) => o.startsWith(prefix));
      return f.length ? f.map((o) => ({ value: o, label: o })) : null;
    },
    handler: async (args, ctx) => runReview(args, ctx),
  });
}

