 */

export interface ClassifyResult {
  scope: "inline" | "delegate";
  tier: "trivial" | "standard" | "hard";
  suggestedRole: string;
  reasons: string[];
}

const ROLE_KEYWORDS: Record<string, string[]> = {
  frontend: ["react", "vue", "angular", "svelte", "nextjs", "next.js", "ui", "css", "html", "tailwind", "component", "page"],
  backend: ["api", "server", "database", "sql", "rest", "graphql", "node", "python", "express", "django", "orm"],
  devops: ["docker", "k8s", "kubernetes", "ci", "cd", "terraform", "aws", "gcp", "azure", "deploy", "infra", "pipeline"],
  tester: ["test", "qa", "e2e", "jest", "cypress", "playwright", "coverage", "fixture"],
