  architect: ["architect", "design", "schema", "topology", "pattern", "system design", "microservice", "monolith"],
};

const HARD_TIERS = ["auth", "security", "migration", "payment", "oauth", "jwt", "encrypt", "secrets", "pii", "production", "billing"];

export function classifyTask(text: string): ClassifyResult {
  const lower = text.toLowerCase();
  const words = lower.split(/[\s,;:.()\[\]{}]+/).filter(Boolean);

  const fileCount = (lower.match(/\b\d+\s+files?\b/i) || []);
  const explicitFileCount = fileCount.length > 0 ? parseInt(fileCount[0].split(/\s+/)[0]) : 0;

  const inline = explicitFileCount > 0 && explicitFileCount <= 3;
  const mechanical = words.some((w) => ["rename", "format", "lint", "fix", "typo", "update"].includes(w));
  const delegate = explicitFileCount > 3 || words.some((w) => ["refactor", "migrate", "redesign", "rewrite", "multi", "cross-module"].includes(w));

  const scope: "inline" | "delegate" = delegate ? "delegate" : inline ? "inline" : "delegate";

  const hardReason = words.filter((w) => HARD_TIERS.includes(w));
  const tier: "trivial" | "standard" | "hard" =
    hardReason.length > 0 ? "hard" : mechanical ? "trivial" : "standard";

  const roleMatches: string[] = [];
  const roleReasons: string[] = [];
  for (const [role, keywords] of Object.entries(ROLE_KEYWORDS)) {
    const hits = keywords.filter((k) => lower.includes(k));
    if (hits.length > 0) {
      roleMatches.push(role);
      roleReasons.push(`${role}: ${hits.join(", ")}`);
    }
  }

  const suggestedRole = roleMatches[0] || "developer";
  const reasons = [
    `scope=${scope}`,
    `tier=${tier}`,
    ...(explicitFileCount > 0 ? [`file_count=${explicitFileCount}`] : []),
    ...roleReasons,
  ];

  return { scope, tier, suggestedRole, reasons };
}

