display.text:
/**
 * build-bus — append-only JSON-Lines message bus.
 * Pure module (no pi imports). Atomic writes, zero-trust audit trail.
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync, renameSync, unlinkSync } from "node:fs";
import { dirname, join } from "node:path";
import { homedir } from "node:os";
import { createHash } from "node:crypto";

export interface BusMessage {
  id: string;
  ts: number;
  from: string;
  type: string;
  payload: unknown;
  correlationId?: string;
  contentHash: string;
}

export interface BusAck {
  id: string;
  by: string;
  ts: number;
}

export interface ReadOptions {
  since?: number;
  from?: string;
  type?: string;
  limit?: number;
}

const DEFAULT_DIR = join(homedir(), ".pi", "build-bus");
const BUS_FILE = "bus.jsonl";

function busPath(dir?: string): string {
  const base = dir || process.env.BUILD_BUS_DIR || DEFAULT_DIR;
  return join(base, BUS_FILE);
}

function contentHash(data: unknown): string {
  const canonical = JSON.stringify(data);
  return createHash("sha256").update(canonical).digest("hex").slice(0, 16);
}

function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}

export function postMessage(
  msg: { from: string; type: string; payload: unknown; correlationId?: string },
  dir?: string,
): BusMessage {
  const entry: BusMessage = {
    id: generateId(),
    ts: Date.now(),
    from: msg.from,
    type: msg.type,
    payload: msg.payload,
    correlationId: msg.correlationId,
    contentHash: contentHash(msg.payload),
  };

  const path = busPath(dir);
  const dirPath = dirname(path);
  if (!existsSync(dirPath)) {
    mkdirSync(dirPath, { recursive: true });
  }

  const tmpPath = `${path}.tmp-${entry.id}`;
  const line = JSON.stringify(entry) + "\n";

  writeFileSync(tmpPath, line, { flag: "wx" });
  try {
    if (existsSync(path)) {
      const existing = readFileSync(path, "utf-8");
      writeFileSync(tmpPath, existing + line, "utf-8");
    } else {
      writeFileSync(tmpPath, line, "utf-8");
    }
    renameSync(tmpPath, path);
  } catch (e) {
    try { unlinkSync(tmpPath); } catch { /* ignore cleanup failure */ }
    throw e;
  }

  return entry;
}

export function readMessages(options: ReadOptions = {}, dir?: string): BusMessage[] {
  const path = busPath(dir);
  if (!existsSync(path)) return [];

  const raw = readFileSync(path, "utf-8");
  const lines = raw.split(/\n+/).filter((l) => l.trim());
  const messages: BusMessage[] = [];

  for (const line of lines) {
    try {
      const msg = JSON.parse(line) as BusMessage;
      if (options.since && msg.ts < options.since) continue;
      if (options.from && msg.from !== options.from) continue;
      if (options.type && msg.type !== options.type) continue;
      messages.push(msg);
    } catch {
      /* skip corrupt lines */
    }
  }

  if (options.limit && options.limit > 0) {
    return messages.slice(-options.limit);
  }
  return messages;
}

export function tail(n: number, dir?: string): BusMessage[] {
  const path = busPath(dir);
  if (!existsSync(path)) return [];

  const raw = readFileSync(path, "utf-8");
  const lines = raw.split(/\n+/).filter((l) => l.trim());

  const result: BusMessage[] = [];
  const slice = lines.slice(-n);
  for (const line of slice) {
    try {
      result.push(JSON.parse(line) as BusMessage);
    } catch {
      /* skip corrupt lines */
    }
  }
  return result;
}

export function ack(id: string, by: string, dir?: string): BusAck {
  const ackEntry: BusAck = {
    id,
    by,
    ts: Date.now(),
  };

  const path = busPath(dir);
  const dirPath = dirname(path);
  if (!existsSync(dirPath)) {
    mkdirSync(dirPath, { recursive: true });
  }

  const tmpPath = `${path}.tmp-ack-${Date.now()}`;
  const line = JSON.stringify({ _ack: ackEntry }) + "\n";

  writeFileSync(tmpPath, line, { flag: "wx" });
  try {
    if (existsSync(path)) {
      const existing = readFileSync(path, "utf-8");
      writeFileSync(tmpPath, existing + line, "utf-8");
    } else {
      writeFileSync(tmpPath, line, "utf-8");
    }
    renameSync(tmpPath, path);
  } catch (e) {
    try { unlinkSync(tmpPath); } catch { /* ignore */ }
    throw e;
  }

  return ackEntry;
}

