import { test } from "node:test";
import { strict as assert } from "node:assert";
import { join } from "node:path";
import { mkdirSync, existsSync, rmSync } from "node:fs";

const TMP_DIR = join(process.cwd(), "tmp", "bus-test-" + Date.now());

function busDir() {
  return TMP_DIR;
}

async function importBus() {
  const mod = await import("../extensions/build-bus/bus.ts");
  return mod;
}

async function importClassify() {
  const mod = await import("../extensions/swarm/classify.ts");
  return mod;
}

async function importGate() {
  const mod = await import("../extensions/swarm/gate.ts");
  return mod;
}

test("bus: post 3 messages, read back 3, ack works", async () => {
  mkdirSync(TMP_DIR, { recursive: true });
  try {
    const { postMessage, readMessages, ack } = await importBus();

    const m1 = postMessage({ from: "agent-a", type: "task", payload: { desc: "first" } }, busDir());
    const m2 = postMessage({ from: "agent-b", type: "status", payload: { done: true } }, busDir());
    const m3 = postMessage({ from: "agent-a", type: "task", payload: { desc: "second" }, correlationId: m1.id }, busDir());

    assert.ok(m1.id);
    assert.ok(m1.contentHash);
    assert.strictEqual(m1.from, "agent-a");
    assert.strictEqual(m2.from, "agent-b");
    assert.strictEqual(m3.correlationId, m1.id);

    const all = readMessages({}, busDir());
    assert.strictEqual(all.length, 3);

    const readBack = readMessages({}, busDir());
    assert.ok(readBack.every((m) => m.id && m.ts && m.from && m.type && m.contentHash));

    const ackEntry = ack(m1.id, "supervisor", busDir());
    assert.strictEqual(ackEntry.id, m1.id);
    assert.strictEqual(ackEntry.by, "supervisor");
  } finally {
    if (existsSync(TMP_DIR)) rmSync(TMP_DIR, { recursive: true });
  }
});

test("classify: auth migration across 8 files => delegate/hard/security", async () => {
  const { classifyTask } = await importClassify();
  const result = classifyTask("add auth migration across 8 files");
  assert.strictEqual(result.scope, "delegate");
  assert.strictEqual(result.tier, "hard");
  assert.strictEqual(result.suggestedRole, "security");
  assert.ok(result.reasons.includes("tier=hard"));
});

test("gate: missing evidence => pass:false", async () => {
  const { verificationGate } = await importGate();
  const result = verificationGate({});
  assert.strictEqual(result.pass, false);
  assert.ok(result.missing.includes("build"));
  assert.ok(result.missing.includes("test"));
  assert.ok(result.missing.includes("lint"));
});

test("gate: all evidence passed => pass:true", async () => {
  const { verificationGate } = await importGate();
  const result = verificationGate({
    build: { passed: true, summary: "ok" },
    test: { passed: true, summary: "ok" },
    lint: { passed: true, summary: "ok" },
  });
  assert.strictEqual(result.pass, true);
  assert.strictEqual(result.missing.length, 0);
});

