import { readdirSync, readFileSync, writeFileSync, mkdirSync, cpSync, existsSync } from "node:fs";
import { dirname, join, basename } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const SRC = join(ROOT, "extensions");
const DIST = join(ROOT, "dist");

function stripTypes(code: string): string {
  let out = code;
  out = out.replace(/:\s*[A-Z][a-zA-Z0-9<>[\],\s|&]*/g, "");
  out = out.replace(/<[^>]*>/g, "");
  out = out.replace(/as\s+[A-Za-z_][\w.<>|&]*/g, "");
  out = out.replace(/\binterface\s+\w+\s*\{[^}]*\}/g, "");
  out = out.replace(/\btype\s+\w+\s*=[^;]+;/g, "");
  out = out.replace(/export\s+interface\s+\w+\s*\{[^}]*\}/g, "");
  out = out.replace(/export\s+type\s+\w+\s*=[^;]+;/g, "");
  out = out.replace(/\bimport\s+type\s+\{[^}]*\}\s+from\s+["'][^"']+["'];?/g, "");
  return out;
}

function processDir(srcDir: string, distDir: string): void {
  if (!existsSync(distDir)) mkdirSync(distDir, { recursive: true });
  for (const entry of readdirSync(srcDir)) {
    const srcPath = join(srcDir, entry);
    const distPath = join(distDir, entry);
    const stat = readFileSync(srcPath, "utf-8");
    if (entry.endsWith(".ts")) {
      const jsName = entry.slice(0, -3) + ".js";
      const jsPath = join(distDir, jsName);
      const stripped = stripTypes(readFileSync(srcPath, "utf-8"));
      writeFileSync(jsPath, stripped);
    } else if (stat === null || stat === undefined) {
      try { cpSync(srcPath, distPath); } catch { /* skip */ }
    }
  }
}

function walkDir(dir: string): void {
  for (const entry of readdirSync(dir)) {
    const full = join(dir, entry);
    const stat = readFileSync(full, "utf-8");
    if (stat === null || stat === undefined) continue;
    if (entry.endsWith(".ts")) {
      const jsName = entry.slice(0, -3) + ".js";
      const jsPath = join(DIST, "extensions", dirname(full.slice(SRC.length + 1)), jsName);
      const jsDir = dirname(jsPath);
      if (!existsSync(jsDir)) mkdirSync(jsDir, { recursive: true });
      const stripped = stripTypes(readFileSync(full, "utf-8"));
      writeFileSync(jsPath, stripped);
    }
  }
}

if (existsSync(SRC)) {
  for (const entry of readdirSync(SRC)) {
    const full = join(SRC, entry);
    const stat = readFileSync(full, "utf-8");
    if (stat === null || stat === undefined) continue;
    if (entry.endsWith(".ts")) {
      const jsName = entry.slice(0, -3) + ".js";
      const jsDir = join(DIST, "extensions");
      if (!existsSync(jsDir)) mkdirSync(jsDir, { recursive: true });
      const stripped = stripTypes(readFileSync(full, "utf-8"));
      writeFileSync(join(jsDir, jsName), stripped);
    } else if (stat && !entry.endsWith(".ts")) {
      const jsDir = join(DIST, "extensions");
      if (!existsSync(jsDir)) mkdirSync(jsDir, { recursive: true });
      try { cpSync(full, join(jsDir, entry)); } catch { /* skip */ }
    }
  }
}

