import { readdirSync, readFileSync, writeFileSync, mkdirSync, cpSync, existsSync, statSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const SRC = join(ROOT, "extensions");
const DIST = join(ROOT, "dist");

function stripTypes(code: string): string {
  let out = code;
  out = out.replace(/:\s*[A-Z][a-zA-Z0-9<>[\],\s|&]*/g, "");
  out = out.replace(/<[^>]*>/g, "");
  out = out.replace(/as\s+[A-Za-z_][\w.<>|&]*/g, "");
  out = out.replace(/\binterface\s+\w+[^}]*\}/g, "");
  out = out.replace(/\btype\s+\w+\s*=[^;]+;/g, "");
  out = out.replace(/\bimport\s+type\s+\{[^}]*\}\s+from\s+["'][^"']+["'];?/g, "");
  return out;
}

function processTsFile(srcPath: string, distPath: string): void {
  const jsName = basename(srcPath).slice(0, -3) + ".js";
  const outPath = join(dirname(distPath), jsName);
  const code = readFileSync(srcPath, "utf-8");
  const stripped = stripTypes(code);
  writeFileSync(outPath, stripped);
}

function copyNonTs(srcPath: string, distPath: string): void {
  const outDir = dirname(distPath);
  if (!existsSync(outDir)) mkdirSync(outDir, { recursive: true });
  cpSync(srcPath, distPath);
}

function walk(src: string, dist: string): void {
  if (!existsSync(dist)) mkdirSync(dist, { recursive: true });
  const entries = readdirSync(src);
  for (const entry of entries) {
    const srcPath = join(src, entry);
    const distPath = join(dist, entry);
    const stat = statSync(srcPath);
    if (stat.isDirectory()) {
      walk(srcPath, distPath);
    } else if (entry.endsWith(".ts")) {
      processTsFile(srcPath, distPath);
    } else {
      copyNonTs(srcPath, distPath);
    }
  }
}

walk(SRC, join(DIST, "extensions"));
console.log("Stripped types from extensions/*.ts -> dist/extensions/*.js");

