/**
 * swarm/gate — verification gate for swarm task completion.
 * Pure module (no pi imports).
 */

export interface VerificationEvidence {
  passed: boolean;
  summary: string;
}

export interface VerificationGateResult {
  pass: boolean;
  missing: string[];
}

const REQUIRED_GATES = ["build", "test", "lint"] as const;

export function verificationGate(evidence: Record<string, VerificationEvidence | undefined>): VerificationGateResult {
  const missing: string[] = [];

  for (const gate of REQUIRED_GATES) {
    const entry = evidence[gate];
    if (!entry || !entry.passed) {
      missing.push(gate);
    }
  }

  return {
    pass: missing.length === 0,
    missing,
  };
}

