/**
 * build-bus — pi extension wrapping the bus.ts message bus.
 * Tools: bus_post, bus_read, bus_tail, bus_ack
 * Command: /bus post|read|tail|ack
 */

import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { Type } from "@earendil-works/pi-ai";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import {
  postMessage as busPost,
  readMessages as busRead,
  tail as busTail,
  ack as busAck,
} from "./bus.ts";

const baseDir = dirname(fileURLToPath(import.meta.url));

const ACTIONS = ["post", "read", "tail", "ack"] as const;

function busDir(): string {
  return process.env.BUILD_BUS_DIR || join(process.env.HOME || ".pi", "build-bus");
}

export default function buildBusExtension(pi: ExtensionAPI) {
  pi.on("resources_discover", async () => {
    const skillPath = join(baseDir, "SKILL.md");
    return { skillPaths: [skillPath] };
  });

  pi.registerTool({
    name: "bus_post",
    label: "Bus Post",
    description: "Post a message to the build-bus (inter-agent message bus). from, type, payload required.",
    promptSnippet: "Post a message to the build-bus",
    promptGuidelines: [
      "Use bus_post to publish task assignments, status updates, or coordination messages to other agents.",
    ],
    parameters: Type.Object({
      from: Type.String({ description: "Sender identifier" }),
      type: Type.String({ description: "Message type" }),
      payload: Type.Unknown({ description: "Message payload (JSON-serializable)" }),
      correlationId: Type.Optional(Type.String({ description: "Correlation ID for linked messages" })),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const entry = busPost(
        {
          from: params.from,
          type: params.type,
          payload: params.payload,
          correlationId: params.correlationId,
        },
        busDir(),
      );
      return {
        content: [{ type: "text", text: JSON.stringify(entry, null, 2) }],
        details: entry,
      };
    },
  });

  pi.registerTool({
    name: "bus_read",
    label: "Bus Read",
    description: "Read messages from the build-bus with optional filters.",
    promptSnippet: "Read messages from the build-bus",
    promptGuidelines: ["Use bus_read to inspect the bus with filters like since, from, type, limit."],
    parameters: Type.Object({
      since: Type.Optional(Type.Number({ description: "Unix ms timestamp — only messages after this" })),
      from: Type.Optional(Type.String({ description: "Filter by sender" })),
      type: Type.Optional(Type.String({ description: "Filter by message type" })),
      limit: Type.Optional(Type.Number({ description: "Max messages to return (0 = all)" })),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const messages = busRead(
        {
          since: params.since,
          from: params.from,
          type: params.type,
          limit: params.limit,
        },
        busDir(),
      );
      return {
        content: [{ type: "text", text: JSON.stringify(messages, null, 2) }],
        details: { count: messages.length },
      };
    },
  });

  pi.registerTool({
    name: "bus_tail",
    label: "Bus Tail",
    description: "Tail the last N messages from the build-bus.",
    promptSnippet: "Tail the build-bus for recent messages",
    promptGuidelines: ["Use bus_tail to quickly inspect recent bus activity."],
    parameters: Type.Object({
      n: Type.Number({ description: "Number of recent messages to return", minimum: 1, maximum: 500 }),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const messages = busTail(params.n, busDir());
      return {
        content: [{ type: "text", text: JSON.stringify(messages, null, 2) }],
        details: { count: messages.length },
      };
    },
  });

  pi.registerTool({
    name: "bus_ack",
    label: "Bus Ack",
    description: "Acknowledge a bus message by ID.",
    promptSnippet: "Acknowledge a build-bus message",
    promptGuidelines: ["Use bus_ack to mark a message as handled."],
    parameters: Type.Object({
      id: Type.String({ description: "Message ID to acknowledge" }),
      by: Type.String({ description: "Acknowledging agent identifier" }),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const ackEntry = busAck(params.id, params.by, busDir());
      return {
        content: [{ type: "text", text: JSON.stringify(ackEntry, null, 2) }],
        details: ackEntry,
      };
    },
  });

  pi.registerCommand("bus", {
    description: "Build-bus: post|read|tail|ack [args]",
    getArgumentCompletions: (prefix: string) => {
      const f = ACTIONS.filter((a) => a.startsWith(prefix));
      return f.length ? f.map((a) => ({ value: a, label: a })) : null;
    },
    handler: async (args, ctx) => {
      const parts = args.trim().split(/\s+/);
      const action = parts[0] || "tail";
      const rest = parts.slice(1).join(" ");

      switch (action) {
        case "post": {
          const [from, type, ...payloadParts] = rest.split(/\s+/);
          if (!from || !type) {
            pi.sendUserMessage([{ type: "text", text: "Usage: /bus post <from> <type> <payload>" }], { triggerTurn: false });
            return;
          }
          const payload = payloadParts.join(" ") || "";
          const entry = busPost({ from, type, payload }, busDir());
          pi.sendUserMessage([{ type: "text", text: JSON.stringify(entry, null, 2) }], { triggerTurn: false });
          break;
        }
        case "read": {
          const messages = busRead({ limit: 20 }, busDir());
          pi.sendUserMessage([{ type: "text", text: JSON.stringify(messages, null, 2) }], { triggerTurn: false });
          break;
        }
        case "tail": {
          const n = parseInt(rest) || 10;
          const messages = busTail(n, busDir());
          pi.sendUserMessage([{ type: "text", text: JSON.stringify(messages, null, 2) }], { triggerTurn: false });
          break;
        }
        case "ack": {
          const [id, by] = rest.split(/\s+/);
          if (!id || !by) {
            pi.sendUserMessage([{ type: "text", text: "Usage: /bus ack <id> <by>" }], { triggerTurn: false });
            return;
          }
          const ackEntry = busAck(id, by, busDir());
          pi.sendUserMessage([{ type: "text", text: JSON.stringify(ackEntry, null, 2) }], { triggerTurn: false });
          break;
        }
        default:
          pi.sendUserMessage([{ type: "text", text: `Unknown action: ${action}. Use: post|read|tail|ack` }], { triggerTurn: false });
      }
    },
  });
}

