/**
 * swarm — pi extension for swarm routing and verification.
 * Tools: swarm_route, swarm_verify
 * Command: /swarm route|verify
 */

import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { Type } from "@earendil-works/pi-ai";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { classifyTask } from "./classify.ts";
import { verificationGate } from "./gate.ts";
import { postMessage } from "../build-bus/bus.ts";

const baseDir = dirname(fileURLToPath(import.meta.url));

function busDir(): string {
  return process.env.BUILD_BUS_DIR || join(process.env.HOME || ".pi", "build-bus");
}

export default function swarmExtension(pi: ExtensionAPI) {
  pi.on("resources_discover", async () => {
    const skillPath = join(baseDir, "SKILL.md");
    return { skillPaths: [skillPath] };
  });

  pi.registerTool({
    name: "swarm_route",
    label: "Swarm Route",
    description:
      "Classify a task and post a routing decision to the build-bus. Returns scope, tier, suggestedRole, and reasons.",
    promptSnippet: "Route a task to the appropriate swarm agent",
    promptGuidelines: [
      "Use swarm_route when a task crosses file/module boundaries and should be delegated.",
      "The routing decision is posted to the build-bus so other agents can see task assignments.",
    ],
    parameters: Type.Object({
      task: Type.String({ description: "Task description text to classify" }),
      from: Type.String({ description: "Calling agent identifier", default: "swarm" }),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const decision = classifyTask(params.task);
      const busEntry = postMessage(
        {
          from: params.from,
          type: "swarm.route",
          payload: decision,
          correlationId: _id,
        },
        busDir(),
      );
      return {
        content: [{ type: "text", text: JSON.stringify({ ...decision, busEntryId: busEntry.id }, null, 2) }],
        details: { ...decision, busEntryId: busEntry.id },
      };
    },
  });

  pi.registerTool({
    name: "swarm_verify",
    label: "Swarm Verify",
    description:
      "Run the verification gate. Pass evidence for build, test, and lint gates. Returns pass/fail and missing gates.",
    promptSnippet: "Verify build/test/lint evidence before declaring a task done",
    promptGuidelines: [
      "Use swarm_verify at the end of any non-trivial task. No 'done' claim without fresh build+test evidence.",
    ],
    parameters: Type.Object({
      buildEvidence: Type.Optional(Type.Object({
        passed: Type.Boolean(),
        summary: Type.String(),
      })),
      testEvidence: Type.Optional(Type.Object({
        passed: Type.Boolean(),
        summary: Type.String(),
      })),
      lintEvidence: Type.Optional(Type.Object({
        passed: Type.Boolean(),
        summary: Type.String(),
      })),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const evidence = {
        build: params.buildEvidence,
        test: params.testEvidence,
        lint: params.lintEvidence,
      };
      const result = verificationGate(evidence);
      const status = result.pass ? "PASS" : "FAIL";
      const text = `${status} — missing: ${result.missing.length > 0 ? result.missing.join(", ") : "none"}`;
      return {
        content: [{ type: "text", text }],
        details: result,
        isError: !result.pass,
      };
    },
  });

  pi.registerCommand("swarm", {
    description: "Swarm: route <task> | verify",
    getArgumentCompletions: (prefix: string) => {
      const f = ["route", "verify"].filter((a) => a.startsWith(prefix));
      return f.length ? f.map((a) => ({ value: a, label: a })) : null;
    },
    handler: async (args, ctx) => {
      const parts = args.trim().split(/\s+/);
      const action = parts[0] || "route";
      const rest = parts.slice(1).join(" ");

      switch (action) {
        case "route": {
          if (!rest) {
            pi.sendUserMessage([{ type: "text", text: "Usage: /swarm route <task description>" }], { triggerTurn: false });
            return;
          }
          const decision = classifyTask(rest);
          const busEntry = postMessage(
            { from: ctx.hasUI ? "cli" : "agent", type: "swarm.route", payload: decision },
            busDir(),
          );
          const summary = `Route: ${decision.scope} / ${decision.tier} / ${decision.suggestedRole}
Reasons: ${decision.reasons.join("; ")}
Bus ID: ${busEntry.id}`;
          pi.sendUserMessage([{ type: "text", text: summary }], { triggerTurn: false });
          break;
        }
        case "verify": {
          const result = verificationGate({});
          const status = result.pass ? "PASS" : "FAIL";
          const text = `${status} — missing: ${result.missing.length > 0 ? result.missing.join(", ") : "none"}`;
          pi.sendUserMessage([{ type: "text", text }], { triggerTurn: false });
          break;
        }
        default:
          pi.sendUserMessage([{ type: "text", text: `Unknown action: ${action}. Use: route|verify` }], { triggerTurn: false });
      }
    },
  });
}
